import{_ as t,o as i,c as a,ah as o}from"./chunks/framework.ojwJKwrc.js";const u=JSON.parse('{"title":"Simulator Optimization Algorithms","description":"","frontmatter":{},"headers":[],"relativePath":"internals/optimizations.md","filePath":"internals/optimizations.md"}'),n={name:"internals/optimizations.md"};function r(s,e,d,l,c,h){return i(),a("div",null,[...e[0]||(e[0]=[o(`<h1 id="simulator-optimization-algorithms" tabindex="-1">Simulator Optimization Algorithms <a class="header-anchor" href="#simulator-optimization-algorithms" aria-label="Permalink to &quot;Simulator Optimization Algorithms&quot;">​</a></h1><p>Celox applies optimizations across multiple layers from compile time to runtime to accelerate simulation. SIR optimization passes can be individually enabled/disabled via <code>OptimizeOptions</code>. The native x86-64 backend applies additional MIR-level optimizations automatically. The Cranelift backend optimization level is separately configurable via <code>CraneliftOptLevel</code>.</p><h2 id="_1-logic-layer-slt-optimizations" tabindex="-1">1. Logic Layer (SLT) Optimizations <a class="header-anchor" href="#_1-logic-layer-slt-optimizations" aria-label="Permalink to &quot;1. Logic Layer (SLT) Optimizations&quot;">​</a></h2><p>These optimizations are applied during the stage where RTL logic expressions are analyzed.</p><h3 id="_1-1-global-hash-consing" tabindex="-1">1.1 Global Hash Consing <a class="header-anchor" href="#_1-1-global-hash-consing" aria-label="Permalink to &quot;1.1 Global Hash Consing&quot;">​</a></h3><p>Expressions (<code>SLTNode</code>) with identical logical structure are deduplicated into shared instances across all modules and all <code>always_comb</code> blocks. This reduces memory usage and improves the efficiency of subsequent hoisting.</p><h3 id="_1-2-topological-hoisting" tabindex="-1">1.2 Topological Hoisting <a class="header-anchor" href="#_1-2-topological-hoisting" aria-label="Permalink to &quot;1.2 Topological Hoisting&quot;">​</a></h3><p>Shared subexpressions referenced multiple times are moved forward in the instruction sequence so they are evaluated only once at the beginning of the simulation cycle. This significantly reduces redundant <code>Load</code> instructions and the number of operations.</p><h2 id="_2-structural-layer-sir-optimizations" tabindex="-1">2. Structural Layer (SIR) Optimizations <a class="header-anchor" href="#_2-structural-layer-sir-optimizations" aria-label="Permalink to &quot;2. Structural Layer (SIR) Optimizations&quot;">​</a></h2><p>These are pass-based optimizations applied to the generated instruction sequence (SIR).</p><h3 id="_2-1-load-store-coalescing" tabindex="-1">2.1 Load/Store Coalescing <a class="header-anchor" href="#_2-1-load-store-coalescing" aria-label="Permalink to &quot;2.1 Load/Store Coalescing&quot;">​</a></h3><ul><li><strong>Load Coalescing</strong>: Merges multiple <code>Load</code> operations to adjacent bit ranges at the same address into a single wider <code>Load</code>.</li><li><strong>Store Coalescing</strong>: Combines writes to consecutive bit ranges at the same address using a <code>Concat</code> instruction, then executes them as a single <code>Store</code>.</li></ul><h3 id="_2-2-redundant-load-elimination-rle-forwarding" tabindex="-1">2.2 Redundant Load Elimination (RLE / Forwarding) <a class="header-anchor" href="#_2-2-redundant-load-elimination-rle-forwarding" aria-label="Permalink to &quot;2.2 Redundant Load Elimination (RLE / Forwarding)&quot;">​</a></h3><p>Tracks values that have been loaded into registers or stored, and eliminates reloads to the same address by reusing the existing register value.</p><h3 id="_2-3-commit-optimization" tabindex="-1">2.3 Commit Optimization <a class="header-anchor" href="#_2-3-commit-optimization" aria-label="Permalink to &quot;2.3 Commit Optimization&quot;">​</a></h3><ul><li><strong>Commit Sinking</strong>: Pushes <code>Commit</code> instructions in merge blocks down into preceding <code>Store</code> instructions to combine them.</li><li><strong>Inline Forwarding</strong>: Replaces generated <code>Commit</code> instructions with direct <code>Store</code> instructions where possible, eliminating unnecessary copies between buffers.</li></ul><h3 id="_2-4-dead-store-elimination" tabindex="-1">2.4 Dead Store Elimination <a class="header-anchor" href="#_2-4-dead-store-elimination" aria-label="Permalink to &quot;2.4 Dead Store Elimination&quot;">​</a></h3><p>Detects and removes writes to the Working region that are never referenced.</p><h3 id="_2-5-instruction-scheduling" tabindex="-1">2.5 Instruction Scheduling <a class="header-anchor" href="#_2-5-instruction-scheduling" aria-label="Permalink to &quot;2.5 Instruction Scheduling&quot;">​</a></h3><p>Reorders instructions while preserving inter-instruction dependencies (RAW/WAR/WAW), taking into account processor execution ports and memory latency.</p><h3 id="_2-6-scheduler-level-store-coalescing" tabindex="-1">2.6 Scheduler-level Store Coalescing <a class="header-anchor" href="#_2-6-scheduler-level-store-coalescing" aria-label="Permalink to &quot;2.6 Scheduler-level Store Coalescing&quot;">​</a></h3><p>During scheduling, consecutive DAG nodes targeting the same variable at the same topological layer are reordered to be adjacent. When contiguous bit ranges of the same variable are detected, they are merged into a single <code>Concat</code> + <code>Store</code> at the SIR level, reducing the number of memory writes. Controlled by <code>SirPass::CoalesceStores</code>.</p><h3 id="_2-7-global-value-numbering-gvn" tabindex="-1">2.7 Global Value Numbering (GVN) <a class="header-anchor" href="#_2-7-global-value-numbering-gvn" aria-label="Permalink to &quot;2.7 Global Value Numbering (GVN)&quot;">​</a></h3><p>Deduplicates SIR instructions with identical operands and eliminates dead code. Controlled by <code>SirPass::Gvn</code>.</p><h3 id="_2-8-concat-folding" tabindex="-1">2.8 Concat Folding <a class="header-anchor" href="#_2-8-concat-folding" aria-label="Permalink to &quot;2.8 Concat Folding&quot;">​</a></h3><p>Folds redundant <code>Concat</code> operations — e.g., when a <code>Concat</code> reassembles slices of the same register in their original order, the Concat is eliminated. Controlled by <code>SirPass::ConcatFolding</code>.</p><h3 id="_2-9-xor-chain-folding" tabindex="-1">2.9 XOR Chain Folding <a class="header-anchor" href="#_2-9-xor-chain-folding" aria-label="Permalink to &quot;2.9 XOR Chain Folding&quot;">​</a></h3><p>Detects and folds XOR reduction chains into more efficient patterns. Controlled by <code>SirPass::XorChainFolding</code>.</p><h3 id="_2-10-vectorize-concat" tabindex="-1">2.10 Vectorize Concat <a class="header-anchor" href="#_2-10-vectorize-concat" aria-label="Permalink to &quot;2.10 Vectorize Concat&quot;">​</a></h3><p>Vectorizes <code>Concat</code> patterns in combinational blocks — recognizes repeated similar operations across bit ranges and replaces them with wider operations. Controlled by <code>SirPass::VectorizeConcat</code>.</p><h3 id="_2-11-split-coalesced-stores" tabindex="-1">2.11 Split Coalesced Stores <a class="header-anchor" href="#_2-11-split-coalesced-stores" aria-label="Permalink to &quot;2.11 Split Coalesced Stores&quot;">​</a></h3><p>Splits wide coalesced stores back into narrower ones after the reschedule pass, when the split form is more efficient for the backend. Controlled by <code>SirPass::SplitCoalescedStores</code>.</p><h3 id="_2-12-partial-forward" tabindex="-1">2.12 Partial Forward <a class="header-anchor" href="#_2-12-partial-forward" aria-label="Permalink to &quot;2.12 Partial Forward&quot;">​</a></h3><p>Partial store-load forwarding in combinational blocks. When a store covers part of a subsequent load&#39;s range, forwards the known portion and narrows the load. Controlled by <code>SirPass::PartialForward</code>.</p><h3 id="_2-13-identity-store-bypass" tabindex="-1">2.13 Identity Store Bypass <a class="header-anchor" href="#_2-13-identity-store-bypass" aria-label="Permalink to &quot;2.13 Identity Store Bypass&quot;">​</a></h3><p>Detects identity copies (Store→Load roundtrips where the value is unchanged) and registers the source and destination as address aliases in <code>Program::address_aliases</code>. Aliased variables share physical memory, eliminating redundant copies. Controlled by <code>SirPass::IdentityStoreBypass</code>.</p><h3 id="_2-14-tail-call-splitting" tabindex="-1">2.14 Tail-Call Splitting <a class="header-anchor" href="#_2-14-tail-call-splitting" aria-label="Permalink to &quot;2.14 Tail-Call Splitting&quot;">​</a></h3><p>Cranelift uses a 24-bit instruction index internally, limiting a single function to approximately 16M CLIF instructions. Large combinational designs (e.g., wide-bus arithmetic, many coalesced execution units) can exceed this limit.</p><p>When the estimated CLIF instruction count for <code>eval_comb</code> exceeds the threshold (currently 8M, a 50% safety margin), the optimizer splits it into a chain of smaller functions connected by Cranelift&#39;s <code>return_call</code> (tail-call) instruction, which avoids stack growth.</p><p>Three strategies are applied in order of increasing cost:</p><ol><li><strong>EU-boundary splitting</strong>: Splits between execution units. Since <code>RegisterId</code>s are EU-scoped, no live registers need to be forwarded across the split boundary (zero overhead).</li><li><strong>Intra-EU single-block splitting</strong>: For a single-block EU that exceeds the threshold, splits at <code>Store</code> instruction boundaries. A dynamic programming pass minimizes the number of live registers that must be forwarded as tail-call arguments. A cost model (<code>cost_model.rs</code>) estimates per-instruction CLIF cost, calibrated against the actual translator (including quadratic costs for wide shifts, multiplication, and division).</li><li><strong>Memory-spilled multi-block splitting</strong>: For multi-block EUs (containing branches and loops), splits the CFG into chunks with a single-entry-point guarantee. Inter-chunk live registers are passed through a scratch memory region appended to the unified memory buffer, rather than as function arguments. Each chunk is compiled with signature <code>(mem_ptr) -&gt; i64</code>, and cross-chunk edges emit spill stores followed by a tail-call.</li></ol><p>This pass runs even when all SIR passes are disabled (<code>OptimizeOptions::none()</code>) to prevent compilation failures.</p><h2 id="per-pass-control" tabindex="-1">Per-Pass Control <a class="header-anchor" href="#per-pass-control" aria-label="Permalink to &quot;Per-Pass Control&quot;">​</a></h2><p>Each SIR optimization pass can be individually enabled or disabled via the <code>SirPass</code> enum and <code>OptimizeOptions</code>. <code>OptLevel::O0</code> enables only <code>TailCallSplit</code>; <code>OptLevel::O1</code> (default) and <code>O2</code> enable all 18 passes.</p><table tabindex="0"><thead><tr><th><code>SirPass</code> variant</th><th>Pass(es)</th></tr></thead><tbody><tr><td><code>StoreLoadForwarding</code></td><td>Load/Store Coalescing, Redundant Load Elimination (2.1, 2.2)</td></tr><tr><td><code>HoistCommonBranchLoads</code></td><td>Branch-shared load hoisting</td></tr><tr><td><code>BitExtractPeephole</code></td><td><code>(value &gt;&gt; shift) &amp; mask</code> → direct ranged load</td></tr><tr><td><code>OptimizeBlocks</code></td><td>Dead block removal, block merging</td></tr><tr><td><code>SplitWideCommits</code></td><td>Wide commit splitting</td></tr><tr><td><code>CommitSinking</code></td><td>Commit Sinking (2.3)</td></tr><tr><td><code>InlineCommitForwarding</code></td><td>Inline Forwarding (2.3)</td></tr><tr><td><code>EliminateDeadWorkingStores</code></td><td>Dead Store Elimination (2.4)</td></tr><tr><td><code>Reschedule</code></td><td>Instruction Scheduling (2.5)</td></tr><tr><td><code>CoalesceStores</code></td><td>Scheduler-level Store Coalescing (2.6)</td></tr><tr><td><code>Gvn</code></td><td>Global Value Numbering (2.7)</td></tr><tr><td><code>ConcatFolding</code></td><td>Concat Folding (2.8)</td></tr><tr><td><code>XorChainFolding</code></td><td>XOR Chain Folding (2.9)</td></tr><tr><td><code>VectorizeConcat</code></td><td>Vectorize Concat (2.10)</td></tr><tr><td><code>SplitCoalescedStores</code></td><td>Split Coalesced Stores (2.11)</td></tr><tr><td><code>PartialForward</code></td><td>Partial Forward (2.12)</td></tr><tr><td><code>IdentityStoreBypass</code></td><td>Identity Store Bypass (2.13)</td></tr><tr><td><code>TailCallSplit</code></td><td>Tail-Call Splitting (2.14) — enabled even at O0</td></tr></tbody></table><h2 id="_3-machine-layer-mir-optimizations-—-native-backend" tabindex="-1">3. Machine Layer (MIR) Optimizations — Native Backend <a class="header-anchor" href="#_3-machine-layer-mir-optimizations-—-native-backend" aria-label="Permalink to &quot;3. Machine Layer (MIR) Optimizations — Native Backend&quot;">​</a></h2><p>These optimizations are applied in the native x86-64 backend between instruction selection (ISel) and register allocation. They operate on MIR, a word-level SSA IR with virtual registers.</p><h3 id="adaptive-pipeline" tabindex="-1">Adaptive Pipeline <a class="header-anchor" href="#adaptive-pipeline" aria-label="Permalink to &quot;Adaptive Pipeline&quot;">​</a></h3><p>The MIR optimizer adapts its aggressiveness based on register pressure:</p><ul><li><strong>High-pressure (VRegs &gt; 40)</strong>: Full pipeline with 2× iterative core passes, followed by load sinking and live range splitting for maximum optimization.</li><li><strong>Low-pressure (VRegs ≤ 40)</strong>: Lightweight single-pass pipeline (skips load sinking and live range splitting).</li></ul><h3 id="mir-optimization-passes" tabindex="-1">MIR Optimization Passes <a class="header-anchor" href="#mir-optimization-passes" aria-label="Permalink to &quot;MIR Optimization Passes&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Pass</th><th>Description</th></tr></thead><tbody><tr><td>Constant folding</td><td>Evaluate operations with constant operands at compile time</td></tr><tr><td>Constant deduplication</td><td>Merge duplicate <code>LoadImm</code> instructions</td></tr><tr><td>Copy propagation</td><td>Replace uses of <code>Mov</code> destinations with their sources</td></tr><tr><td>Algebraic simplification</td><td>Simplify patterns like <code>x &amp; 0</code> → <code>0</code>, <code>x | 0</code> → <code>x</code>, <code>x ^ 0</code> → <code>x</code>, strength-reduce <code>Mul</code> to shifts</td></tr><tr><td>Redundant mask elimination</td><td>Remove <code>AndImm</code> masks that are provably no-ops (uses known-width tracking)</td></tr><tr><td>Global value numbering (GVN)</td><td>Deduplicate instructions with identical operands (dominator-aware)</td></tr><tr><td>Dead code elimination (DCE)</td><td>Remove instructions whose results are unused</td></tr><tr><td>Lower to immediate forms</td><td>Convert <code>op reg, LoadImm(c)</code> → <code>opImm reg, c</code></td></tr><tr><td>LoadImm sinking</td><td>Move constant loads closer to their uses to reduce register pressure (high-pressure only)</td></tr><tr><td>Live range splitting</td><td>Split long-lived values to improve register allocation (high-pressure only)</td></tr><tr><td>XOR chain to PEXT fusion</td><td>Fold XOR reduction chains into BMI2 <code>PEXT</code> instructions</td></tr><tr><td>If-conversion</td><td>Convert diamond <code>Branch</code> patterns into <code>Select</code> (cmov) for small arms</td></tr><tr><td>CFG simplification</td><td>Thread jumps through empty blocks, eliminate redundant branches</td></tr><tr><td>Value width computation</td><td>Track actual bit widths for narrowing optimizations in the emitter (e.g., 32-bit registers)</td></tr></tbody></table><h2 id="_4-cranelift-backend-options" tabindex="-1">4. Cranelift Backend Options <a class="header-anchor" href="#_4-cranelift-backend-options" aria-label="Permalink to &quot;4. Cranelift Backend Options&quot;">​</a></h2><p>The Cranelift backend optimization level is separately configurable via <code>CraneliftOptLevel</code>:</p><table tabindex="0"><thead><tr><th>Level</th><th>Description</th></tr></thead><tbody><tr><td><code>None</code></td><td>No Cranelift-level optimizations (skips egraph pass)</td></tr><tr><td><code>Speed</code> (default)</td><td>Optimize for execution speed</td></tr><tr><td><code>SpeedAndSize</code></td><td>Optimize for both speed and code size</td></tr></tbody></table><p>Additional Cranelift backend options are available via <code>CraneliftOptions</code>:</p><table tabindex="0"><thead><tr><th>Option</th><th>Type</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>regalloc_algorithm</code></td><td><code>Backtracking</code> / <code>SinglePass</code></td><td><code>Backtracking</code></td><td>Register allocator algorithm. <code>SinglePass</code> is much faster but generates more spills</td></tr><tr><td><code>enable_alias_analysis</code></td><td>bool</td><td><code>true</code></td><td>Alias-aware redundant load optimization during egraph pass</td></tr><tr><td><code>enable_verifier</code></td><td>bool</td><td><code>true</code></td><td>Cranelift IR verifier — disable to save compile time</td></tr></tbody></table><p>For fastest compilation at the cost of simulation performance:</p><div class="language-rust vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Simulator</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">builder</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(code, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Top&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    .</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cranelift_options</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">CraneliftOptions</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">::</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">fast_compile</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">())</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    .</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">build</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">()</span></span></code></pre></div><p>This sets <code>opt_level = None</code>, <code>regalloc_algorithm = SinglePass</code>, disables alias analysis and the verifier.</p><h2 id="_5-execution-layer-behavioral-optimizations" tabindex="-1">5. Execution Layer (Behavioral) Optimizations <a class="header-anchor" href="#_5-execution-layer-behavioral-optimizations" aria-label="Permalink to &quot;5. Execution Layer (Behavioral) Optimizations&quot;">​</a></h2><p>These are dynamic optimizations applied in the simulator&#39;s execution loop.</p><h3 id="_5-1-silent-edge-skipping" tabindex="-1">5.1 Silent Edge Skipping <a class="header-anchor" href="#_5-1-silent-edge-skipping" aria-label="Permalink to &quot;5.1 Silent Edge Skipping&quot;">​</a></h3><p>When events such as clock signals occur but the signal value has not changed, or the trigger condition (rising/falling edge) is not met, evaluation of dependent flip-flops and re-evaluation of associated combinational logic are skipped.</p><h3 id="_5-2-multi-phase-evaluation-separation-of-evaluation-and-update" tabindex="-1">5.2 Multi-Phase Evaluation (Separation of Evaluation and Update) <a class="header-anchor" href="#_5-2-multi-phase-evaluation-separation-of-evaluation-and-update" aria-label="Permalink to &quot;5.2 Multi-Phase Evaluation (Separation of Evaluation and Update)&quot;">​</a></h3><p>When multiple events are triggered simultaneously, all evaluations are performed based on the current values in the Stable region, followed by a bulk update. This guarantees consistent simulation results independent of the order in which events occur.</p>`,66)])])}const m=t(n,[["render",r]]);export{u as __pageData,m as default};
